parameters.jsCode:
const body = $json.body ?? $json;
const execution_mode = $json.executionMode;

// Detect source
const isTypeform = !!body.form_response;

let first_name = "";
let last_name = "";
let email = "";
let phone = "";
let company = "";
let website = "";
let industry = "";
let service = "";
let budget_raw = "";
let description = "";

let utm_source = null;
let utm_medium = null;
let utm_campaign = null;

let typeform_form_id = null;
let typeform_token = null;
let submitted_at = null;
let landed_at = null;

// ----------------------
// TYPEFORM PAYLOAD
// ----------------------

if (isTypeform) {

  const fr = body.form_response ?? {};
  const answers = fr.answers ?? [];
  const hidden = fr.hidden ?? {};

  function getByRef(ref) {
    const a = answers.find(x => x.field?.ref === ref);
    if (!a) return "";

    return (
      a.text ??
      a.email ??
      a.phone_number ??
      a.url ??
      (a.choice?.label ?? "") ??
      ""
    );
  }

  first_name = getByRef("first_name").trim();
  last_name  = getByRef("last_name").trim();
  email      = getByRef("business_email").trim().toLowerCase();
  phone      = getByRef("phone_number").trim();
  company    = getByRef("company_name").trim();
  website    = getByRef("company_website").trim();
  industry   = getByRef("industry").trim();
  service    = getByRef("service").trim();
  budget_raw = getByRef("budget").trim();
  description= getByRef("description").trim();

  utm_source = hidden.utm_source ?? null;
  utm_medium = hidden.utm_medium ?? null;
  utm_campaign = hidden.utm_campaign ?? null;

  typeform_form_id = fr.form_id ?? null;
  typeform_token = fr.token ?? null;

  submitted_at = fr.submitted_at ?? null;
  landed_at = fr.landed_at ?? null;

}

// ----------------------
// ANGULAR FORM PAYLOAD
// ----------------------

else {

  first_name = body.firstName?.trim() ?? "";
  last_name  = body.lastName?.trim() ?? "";
  email      = body.email?.trim().toLowerCase() ?? "";
  phone      = body.phone?.trim() ?? "";
  company    = body.company?.trim() ?? "";
  website    = body.website?.trim() ?? "";
  industry   = body.industry?.trim() ?? "";
  service    = body.service?.trim() ?? "";
  budget_raw = String(body.budget ?? "").trim();
  description = body.message?.trim() ?? "";

  submitted_at = body.submittedAt ?? null;
  landed_at = $now;
}

// ----------------------
// BUDGET PARSER
// ----------------------

function parseBudgetUSD(s) {

  if (!s) return null;

  const t = s.toLowerCase()
    .replace(/,/g, "")
    .replace(/\$/g, "")
    .trim();

  const kMatch = t.match(/^(\d+(\.\d+)?)\s*k$/);

  if (kMatch)
    return Math.round(parseFloat(kMatch[1]) * 1000);

  const numMatch = t.match(/(\d+(\.\d+)?)/);

  if (!numMatch)
    return null;

  return Math.round(parseFloat(numMatch[1]));
}

const budget_usd = parseBudgetUSD(budget_raw);

// ----------------------
// BUDGET BUCKET
// ----------------------

function budgetBucket(n) {

  if (n == null) return "unknown";
  if (n < 1000) return "<1k";
  if (n < 5000) return "1k-5k";
  if (n < 15000) return "5k-15k";

  return "15k+";
}

// ----------------------
// DOMAIN EXTRACTION
// ----------------------

const domainFromEmail = email.includes("@")
  ? email.split("@")[1]
  : "";

const domainFromWebsite = website
  .toLowerCase()
  .replace(/^https?:\/\//, "")
  .replace(/^www\./, "")
  .split("/")[0];

const domain = domainFromEmail || domainFromWebsite;

// ----------------------
// LEAD KEY
// ----------------------

const lead_key =
  email ||
  `${company.toLowerCase()}|${domain}`;

// ----------------------
// VALIDATION
// ----------------------

const missing = [];

if (!first_name) missing.push("first_name");
if (!last_name) missing.push("last_name");
if (!company) missing.push("company");
if (!description) missing.push("description");
if (!email && !domain) missing.push("email_or_domain");

// ----------------------
// OUTPUT
// ----------------------

return [
  {
    json: {

      source: isTypeform ? "typeform" : "angular",

      execution_mode: execution_mode ?? "test",

      utm_source,
      utm_medium,
      utm_campaign,

      typeform_form_id,
      typeform_token,

      submitted_at,
      landed_at,

      first_name,
      last_name,
      email,
      phone,
      company,
      website,
      domain,
      industry,
      service,

      budget_raw,
      budget_usd,
      budget_bucket: budgetBucket(budget_usd),

      description,

      lead_key,

      is_valid: missing.length === 0,
      missing_fields: missing.join(", ")

    }
  }
];

const v = $('If valid?').first().json;

let score = 0;
const reasons = [];

const budget = Number(v.budget_usd) || 0;

if (budget >= 15000) {
  score += 40;
  reasons.push("High budget");
} else if (budget >= 5000) {
  score += 20;
  reasons.push("Mid budget");
}

if (v.service === "AI Integration") {
  score += 25;
  reasons.push("AI service interest");
}

if (v.industry === "SaaS") {
  score += 15;
  reasons.push("SaaS industry");
}

const email = String(v.email || "").toLowerCase();
const domain = email.split("@")[1] || "";
const freeDomains = new Set(["gmail.com","yahoo.com","outlook.com","hotmail.com","icloud.com"]);

if (freeDomains.has(domain)) {
  score -= 10;
  reasons.push("Free email domain");
}

score = Math.max(0, Math.min(100, score));

return [{
  json: {
    score,
    score_reasons: reasons
  }
}];

